1	#!/usr/bin/env perl
2	
3	use strict;
4	my $memW="$ARGV[0]";
5	
6	####################################################
7	# Following decoding for the commands
8	#
9	# 7 commands at most - 3 bits encode
10	# write_reg - 3'b000
11	# read_reg  - 3'b001
12	# write_mem - 3'b010
13	# read_mem  - 3'b011
14	# load_mem  - 3'b100
15	# dump_mem  - 3'b101
16	# wait      - 3'b110
17	
18	# Each command is constant width - for the sequencer - 120 bits - pad 0's accordingly
19	# write_req     : cmd_addr_data
20	# read_reg      : cmd_addr_data_bmask_cmpmode_pollattmpt
21	# load/dump_mem : cmd_addr_offset
22	# Write_reg     : 00_00000000_00000000
23	# Read_reg      : 00_00000000_00000000_00000000_00_0000
24	# Load/Dump_mem : 00_0000000000_00000000
25	
26	# Configurable parameters
27	my $read_reg_poll_retries = 50000;
28	my $word_bytes=32/8;
29	my $test_dir = '.';
30	my $output_test_dir = '.';
31	if($memW eq '256'){
32	   print "256 memory width\n";
33	   $word_bytes = 256/8; #This is the number of lines (bytes) read in to produce one line (word) of output
34	   $test_dir = $ARGV[1];
35	} elsif($memW eq '32'){
36	   $test_dir = $ARGV[1];
37	   print "32 memory width\n";
38	}else{
39	   # For VCS simulation, put the input.txn.raw file in the sim directory
40	   print "default 32 memory width\n";
41	   $test_dir = $ARGV[0];
42	}
43	
44	# Creating a hash for the above - command - hex val
45	my %command_hash = (
46	    'write_reg' => '00',
47	    'read_reg'  => '01',
48	    'write_mem' => '02',
49	    'read_mem'  => '03',
50	    'load_mem'  => '04',
51	    'dump_mem'  => '05',
52	    'wait'      => '06',
53	);
54	
55	my %MSEQ_defines;
56	populate_mseq_defines("../../synth_tb/syn_tb_defines.vh", \%MSEQ_defines);
57	
58	my $input_file = "$test_dir/input.txn";
59	my $output_file = "$output_test_dir/input.txn.raw";
60	
61	my $inf;
62	my $ouf;
63	
64	my $load_file_counter = 0;
65	my $dump_file_counter = 0;
66	print "accessing $input_file\n";
67	open ($inf, "<", $input_file) || die "Cannot open $input_file";
68	open ($ouf, ">", $output_file) || die "Cannot open $output_file";
69	
70	# SW Reset sequence from master_seq.sv
71	#write_reg("write_reg 0x27000200 0x00000000", 0); 
72	#write_reg("write_reg 0x27000200 0xffffffff", 0); 
73	#write_reg("write_reg 0x27000200 0x00000000", 0); 
74	#write_reg("write_reg 0x27000200 0xffffffff", 1); 
75	#write_reg("write_reg 0x27000200 0xc0012020", 1); 
76	
77	#my @sw_reset_seq = (
78	#    "write_reg 0x27000200 0x00000000", 
79	#    "write_reg 0x27000200 0xffffffff", 
80	#    "write_reg 0x27000200 0x00000000", 
81	#    "write_reg 0x27000200 0xffffffff", 
82	#    "write_reg 0x27000200 0xc0012020" 
83	#);
84	#
85	#my $cmd;
86	#foreach $cmd (@sw_reset_seq) {
87	## Right now sw_reset_seq only has write_reg
88	#    my @values = split (' ', $cmd);
89	#    my $hex_string = $command_hash{$values[0]};
90	#
91	#    my $address = $values[1];
92	#    my $data = $values[2];
93	#
94	#    $address =~ m/0x(.*)/;
95	#    my $hex_addr = $1;
96	#    $data =~ m/0x(.*)/;
97	#    my $hex_data = $1;
98	#
99	#    $hex_string = $hex_string.$hex_addr.$hex_data;
100	#
101	#    # Pad extra 0's to maintain cmd length of 128 bits
102	#    $hex_string = $hex_string."00000000000000";
103	#    print $ouf "$hex_string\n";
104	#}
105	
106	while(<$inf>)
107	{
108	  my $input_line = $_;
109	  $input_line =~ s/#.*//;
110	  my @values = split (' ', $input_line);
111	  #print "\n" . $input_line . "\n";
112	
113	  my $size = scalar (split(' ', $input_line));
114	  #print "\nSIZE: ". $size . "\n";
115	
116	  if($size != 0) {
117	
118	    my $hex_string = $command_hash{$values[0]};
119	    #print $values[0] . "\t HexVal: " . $hex_string;
120	
121	    if ($values[0] =~ /wait/) {
122	      $hex_string = $hex_string."000000000000000000000000000000";
123	    }
124	    elsif($values[0] =~ /write_reg/) {
125	      if($size != 3) { die "\nERROR: in write_reg command: $input_line\n" };
126	
127	      # For CSB, top 16 bits are misc, lower 16 are addr
128	      my $address = $values[1]; 
129	      my $data = $values[2];
130	
131	      $address =~ m/0x(.*)/;
132	      my $hex_addr = hex($1); 
133	      my $hex_addr_string = sprintf("%08x", $hex_addr);
134	      $data =~ m/0x(.*)/;
135	      my $hex_data = hex($1);
136	      my $hex_data_string = sprintf("%08x", $hex_data);
137	
